code_string = """from qiskit import transpile
from scipy.optimize import minimize

def run_and_analyze(circuit, aer_sim, graph):
    circuit = transpile(circuit, backend=aer_sim)
    num_params = circuit.num_parameters
    initial_params = [0.0] * num_params

    def cost_function(params):
        param_binds = {circuit.parameters[i]: [params[i]] for i in range(num_params)}
        job = aer_sim.run(circuit, parameter_binds=[param_binds], shots=1024)
        counts = job.result().get_counts()
        processed_counts = {key[::-1]: val for key, val in counts.items()}
        exp = compute_expectation(processed_counts, graph)
        return -exp

    result = minimize(cost_function, initial_params, method='COBYLA')
    optimal_params = result.x
    param_binds_final = {circuit.parameters[i]: [optimal_params[i]] for i in range(num_params)}
    job = aer_sim.run(circuit, parameter_binds=[param_binds_final], shots=1024)
    counts = job.result().get_counts()
    processed_counts = {key[::-1]: val for key, val in counts.items()}
    sorted_counts = sorted(processed_counts.items(), key=lambda item: item[1], reverse=True)
    top_two = [bitstring for bitstring, _ in sorted_counts[:2]]
    return top_two
"""
